import{c as i,Q as a,j as s,m as t}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Audio Metadata Repair Script","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/repair-audio-metadata.md","filePath":"scripts/repair-audio-metadata.md","lastUpdated":1780203972000}'),o={name:"scripts/repair-audio-metadata.md"};function r(l,e,d,p,n,c){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="audio-metadata-repair-script" tabindex="-1">Audio Metadata Repair Script <a class="header-anchor" href="#audio-metadata-repair-script" aria-label="Permalink to &quot;Audio Metadata Repair Script&quot;">​</a></h1><p>Run this script with the project Python environment when possible:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Standalone diagnostic and repair helper for audio metadata/container issues. Dry-run is read-only and does not copy or write audio files. Each normal run writes a repair-specific JSON report, styled XLSX workbook, and structured text log under <code>scripts\\audio_repair\\reports</code> by default.</p><p>Use this script when scanning, tag refresh, or genre writing reports suspicious or unreadable metadata, especially for WAV/AIFF/container edge cases. Do not use it as a general tag editor; it is a diagnostic and repair tool for files the script classifies as safe to repair.</p><p>Usage:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_repair\\repair_audio_metadata.py [OPTIONS] [paths ...]</span></span></code></pre></div><p>Inputs:</p><ul><li>positional <code>paths</code>: audio files to inspect or repair.</li><li><code>--folder FOLDER</code>: recursively collect supported audio files from a folder.</li><li><code>--db DB</code>: collect existing audio files from <code>tracks.path</code> in a SQLite library database. The database is opened read-only.</li><li><code>--db-root PATH</code>: only use database paths under this stored root. Can be repeated.</li><li><code>--file-root PATH</code>: replace the matching <code>--db-root</code> prefix with this real filesystem root before checking whether each file exists.</li><li><code>--log LOG</code>: extract post-save readback-failed WAV paths from a project log.</li><li><code>--since TIMESTAMP</code>: only use log lines at or after a timestamp.</li><li><code>--until TIMESTAMP</code>: only use log lines before a timestamp.</li></ul><p>Repair and safety options:</p><ul><li><code>--apply</code>: write repaired files. Default is dry-run.</li><li><code>--backup-dir PATH</code>: backup directory used only with <code>--apply</code>.</li><li><code>--no-backup</code>: apply without full-file backups; use only if another backup exists.</li><li><code>--keep-id3 first|last|none</code>: for WAV repair, choose which readable top-level ID3 chunk to keep. Default is <code>first</code>.</li><li><code>--reason VALUE</code>: in folder or database mode, apply only entries with a stored reason. Can be repeated.</li></ul><p>Run control:</p><ul><li><code>--limit N</code>: process only the first collected paths.</li><li><code>--summary-only</code>: print only the final summary.</li><li><code>--color auto|always|never</code>: colorize status labels.</li><li><code>--out-dir DIR</code>: report output directory. Default is <code>scripts\\audio_repair\\reports</code>.</li><li><code>--file-log PATH</code>: optional console transcript log path overwritten on every run. This is separate from the structured report log.</li><li><code>--no-file-log</code>: disable the optional console transcript log.</li><li><code>--no-report</code>: disable the JSON/XLSX/log report bundle.</li><li><code>--state PATH</code>: explicit folder/database-mode state file.</li><li><code>--workers N</code>: parallel dry-run workers. Apply mode always runs sequentially.</li></ul><p>Default generated structure:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.json</span></span>
<span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.xlsx</span></span>
<span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.log</span></span>
<span class="line"><span>scripts\\audio_repair\\state\\state.&lt;source&gt;.&lt;hash&gt;.json</span></span>
<span class="line"><span>scripts\\audio_repair\\backups\\&lt;filename&gt;.&lt;timestamp&gt;.&lt;suffix&gt;.bak</span></span></code></pre></div><p>The report bundle contains only audio-repair data. It does not include duplicate grouping, delete candidates, Rhythm Lab impact, or any <code>audio_dedup</code> fields. The JSON stores the collected sources, run options, state skips, missing DB-file count, <code>processed_count</code>, <code>state_result_count</code>, <code>result_count</code>, <code>status_counts</code>, <code>reason_counts</code>, <code>problem_summary</code>, and <code>results</code>. In folder or database mode, current entries skipped from the state file are included in the report with <code>source: &quot;state&quot;</code> so repeat runs still show the previous analysis results instead of an empty report. Files processed during the current run use <code>source: &quot;processed&quot;</code>.</p><p>The XLSX workbook is the main review artifact and has three sheets:</p><ul><li><code>Summary</code>: mode, source counts, processed counts, state skips, status counts, and reason counts.</li><li><code>Results</code>: one row per file with action (<code>REPAIR AVAILABLE</code>, <code>REPAIRED</code>, <code>ALREADY REPAIRED</code>, <code>OK</code>, <code>REVIEW MANUALLY</code>, and so on), source, status, reason, path, mode, size delta, ID3 counts, primary action, backup path, state timestamps, and Mutagen summary.</li><li><code>Problems</code>: grouped problem summary matching the terminal output.</li></ul><p>The structured <code>.log</code> mirrors the run-level counts in key-value form for quick grep or shell review.</p><p>Recommended workflow:</p><ol><li>Run a dry run against a small path, folder, log, or database subset.</li><li>Review the generated workbook and the status/reason for every <code>REPAIRABLE</code> entry.</li><li>Run <code>--apply</code> only for the specific reason or file set you intend to fix. Existing dry-run state is reused: non-repairable checked files are skipped, while <code>REPAIRABLE</code> entries remain candidates for repair.</li><li>Keep backups enabled unless you already have an external backup.</li></ol><p>Apply safety sequence:</p><ol><li>Create a full-file backup unless <code>--no-backup</code> was explicitly passed.</li><li>Write the repaired bytes through a temporary sibling file and atomic replace.</li><li>Re-read the repaired file from disk and verify the container structure.</li><li>Run the normal post-write inspection from disk, including format/codec checks when <code>ffprobe</code> is available and Mutagen tag readback.</li><li>Mark the result as <code>REPAIRED</code> only after those checks pass. If verification fails and a backup exists, restore the original file from the backup and mark the result as <code>FAILED</code>.</li><li>Delete the backup after a fully successful repair. If verification fails, restore the original file from backup, then delete the backup after the restore succeeds. A backup remains only if restore or cleanup itself fails.</li></ol><p>Apply-mode CLI output includes the repair action plus backup/write/verify/delete or restore events in the per-file <code>actions=</code> field.</p><p>Examples:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">workers </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reason OVERSIZED_DATA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes\\Abstracted</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root S:\\Music\\Volumes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py .\\music\\track.wav </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">summary</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">only</span></span></code></pre></div><p>Status meanings:</p><ul><li><code>OK</code>: no repair needed.</li><li><code>NOTICE</code>: cosmetic, non-required cleanup; not rewritten.</li><li><code>REPAIRABLE</code>: a safe repair exists (dry-run only reports it).</li><li><code>REPAIRED</code>: apply mode wrote a verified repair.</li><li><code>SUSPICIOUS</code>: format/container or codec mismatch worth a closer look.</li><li><code>TAG-ERROR</code>: tag-read failure without a safe repair path.</li><li><code>BROKEN</code>: the file could not be parsed as the expected container.</li><li><code>FAILED</code>: apply attempted a repair but it could not be written or verified.</li><li><code>UNSUPPORTED</code>: extension outside the repairable WAV/AIFF set; inspected only.</li></ul><p>Reasons:</p><p>In folder or database mode, each result also records an uppercase reason. Use it with <code>--reason</code> to re-run apply against only one class of fix, for example:</p><ul><li><code>OVERSIZED_DATA</code>: a WAV <code>data</code> chunk larger than the audio payload before ID3.</li><li><code>DUPLICATE_ID3</code>: more than one top-level ID3 chunk in a WAV.</li><li><code>EMPTY_ID3</code>: an empty AIFF <code>ID3 </code> chunk that blocks Mutagen reads.</li><li><code>CONTAINER_NORMALIZATION</code>: RIFF/FORM root-size or padding normalization.</li><li><code>EXTENSION_MISMATCH</code>: container/codec does not match the file extension.</li></ul><p><code>--reason</code> is only valid in folder or database mode (it requires the state file). Match the exact reason text shown in the report.</p><p>State behavior:</p><ul><li>State files are used only in <code>--folder</code> and <code>--db</code> mode. Direct path and log runs do not create or reuse state.</li><li>A state entry is current only while the file size and integer modified time still match the file on disk.</li><li>Dry-run skips current state entries and reports their stored status/reason.</li><li>Apply skips current dry-run entries that do not need repair, but still processes current dry-run <code>REPAIRABLE</code> entries.</li><li>After a successful apply repair, the state entry is rewritten with the new file size/modified time, <code>mode: &quot;apply&quot;</code>, <code>status: &quot;REPAIRED&quot;</code>, and <code>message: &quot;repair_applied&quot;</code> so later runs report it as already repaired.</li></ul><p>Exit codes:</p><ul><li><code>0</code>: completed with no <code>FAILED</code> results.</li><li><code>1</code>: at least one file ended in the <code>FAILED</code> status.</li><li><code>2</code>: a usage error, such as <code>--file-root</code> without <code>--db-root</code>, <code>--reason</code> outside state mode, <code>--backup-dir</code> together with <code>--no-backup</code>, or no input paths found.</li></ul>`,36)])])}const k=i(o,[["render",r]]);export{u as __pageData,k as default};
